#include <stdio.h>
int main() {
    int n, q;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    scanf("%d", &q);
    while (q--) {
        int start, end;
        scanf("%d %d", &start, &end);
        int count = 0;
        for (int i = start - 1; i < end; i++) {
            int num = arr[i];
            while (num > 0) {
                if (num % 10 != 4 && num % 10 != 7) {
                    break;
                }
                num /= 10;
            }
            if (num == 0) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

