    if (i == 0) {
        n = parseInt(line);
    } else if (i == 1) {
        arr = line.split(' ').map(num => parseInt(num));
    } else if (i == 2) {
        q = parseInt(line);
    } else {
        let [start, end] = line.split(' ').map(num => parseInt(num));
        let count = 0;
        for (let j = start - 1; j < end; j++) {
            let num = arr[j];
            while (num > 0) {
                if (num % 10 != 4 && num % 10 != 7) {
                    break;
                }
                num = Math.floor(num / 10);
            }
            if (num == 0) {
                count++;
            }
        }
        console.log(count);
        q--;
        if (q == 0) {
